polling_for_completion.code:
async function pollCheckout(checkoutId, expiresAt) {
  const deadline = new Date(expiresAt).getTime();
  while (Date.now() < deadline) {
    await sleep(5000);  // MUST NOT poll more frequently than once per 5 seconds
    const checkout = await callMerchantMCP('get_checkout', { id: checkoutId });
    if (checkout.status === 'completed') {
      return { success: true, order: checkout.order };
    }
    if (checkout.status === 'canceled') {
      return { success: false, reason: 'canceled' };
    }
  }
  return { success: false, reason: 'timeout' };
}
